class Solution {
public:
    vector<long long> unmarkedSumArray(vector<int>& nums, vector<vector<int>>& queries) {
        int n = nums.size();
        vector<bool> marked(n, false);
        vector<long long> unmarkedSums(n);
        long long totalSum = 0;

        for (int i = 0; i < n; i++) {
            totalSum += nums[i];
            unmarkedSums[i] = totalSum;
        }

        vector<long long> answer(queries.size());
        for (int i = 0; i < queries.size(); i++) {
            int index = queries[i][0];
            int k = queries[i][1];
            if (!marked[index]) {
                marked[index] = true;
                totalSum -= nums[index];
            }
            sort(unmarkedSums.begin(), unmarkedSums.end());
            for (int j = 0; j < k && j < n; j++) {
                if (!marked[j]) {
                    marked[j] = true;
                    totalSum -= unmarkedSums[j];
                }
            }
            answer[i] = totalSum;
        }
        return answer;
    }
};
```

